   751	    pub(crate) fn make_usage_ctx(
   752	        usage: &usage::parse::ParseOutput,
   753	    ) -> HashMap<String, tera::Value> {
   754	        let mut usage_ctx: HashMap<String, tera::Value> = HashMap::new();
   755	
   756	        // These values are not escaped or shell-quoted.
   757	        let to_tera_value = |val: &usage::parse::ParseValue| -> tera::Value {
   758	            use tera::Value;
   759	            use usage::parse::ParseValue::*;
   760	            match val {
   761	                MultiBool(v) => Value::from(v.len()),
   762	                MultiString(v) => Value::from(v.to_vec()),
   763	                Bool(v) => Value::from(*v),
   764	                String(v) => Value::from(v.clone()),
   765	            }
   766	        };
   767	
   768	        // The names are converted to snake_case (hyphens become underscores).
   769	        // For example, a flag like "--dry-run" becomes accessible as {{ usage.dry_run }}.
   770	        for (arg, val) in &usage.args {
   771	            let tera_val = to_tera_value(val);
   772	            usage_ctx.insert(arg.name.to_snake_case(), tera_val);
   773	        }
   774	        for (flag, val) in &usage.flags {
   775	            let tera_val = to_tera_value(val);
   776	            usage_ctx.insert(flag.name.to_snake_case(), tera_val);
   777	        }
   778	
   779	        // expose selected subcommand as {{ usage.cmd }}
   780	        if let Some(subcmd) = subcommand_name_from_parse(&usage.cmds) {
   781	            usage_ctx.insert("cmd".to_string(), tera::Value::from(subcmd));
   782	        }
   783	
   784	        usage_ctx
   785	    }
