   787	    /// Build a usage context hashmap from a `usage::Spec` using default values
   788	    /// or sensible fallbacks. Recurses into subcommands so that `{{ usage.X }}`
   789	    /// references don't error during the initial template render (which is only
   790	    /// used for deprecated spec collection — actual execution re-renders via
   791	    /// `parse_run_scripts_with_args` with real parsed values).
   792	    pub fn make_usage_ctx_from_spec_defaults(spec: &usage::Spec) -> HashMap<String, tera::Value> {
   793	        let mut usage_ctx: HashMap<String, tera::Value> = HashMap::new();
   794	
   795	        fn collect_cmd_defaults(cmd: &usage::SpecCommand, ctx: &mut HashMap<String, tera::Value>) {
   796	            for arg in &cmd.args {
   797	                let name = arg.name.to_snake_case();
   798	                if ctx.contains_key(&name) {
   799	                    continue;
   800	                }
   801	                let value = if arg.var {
   802	                    tera::Value::from(arg.default.clone())
   803	                } else if let Some(default) = arg.default.first() {
   804	                    tera::Value::from(default.clone())
   805	                } else {
   806	                    tera::Value::from(String::new())
   807	                };
   808	                ctx.insert(name, value);
   809	            }
   810	
   811	            for flag in &cmd.flags {
   812	                let name = flag.name.to_snake_case();
   813	                if ctx.contains_key(&name) {
   814	                    continue;
   815	                }
   816	                let value = if flag.var {
   817	                    tera::Value::from(flag.default.clone())
   818	                } else if flag.count {
   819	                    tera::Value::from(0)
   820	                } else if let Some(default) = flag.default.first() {
   821	                    default
   822	                        .parse::<bool>()
   823	                        .map_or_else(|_| tera::Value::from(default.clone()), tera::Value::from)
   824	                } else {
   825	                    tera::Value::from(false)
   826	                };
   827	                ctx.insert(name, value);
   828	            }
   829	
   830	            // SpecCommand::subcommands is an IndexMap, so iteration order is deterministic
   831	            for subcmd in cmd.subcommands.values() {
   832	                collect_cmd_defaults(subcmd, ctx);
   833	            }
   834	        }
   835	
   836	        collect_cmd_defaults(&spec.cmd, &mut usage_ctx);
   837	
   838	        if !spec.cmd.subcommands.is_empty() {
   839	            usage_ctx.insert("cmd".to_string(), tera::Value::from(String::new()));
   840	        }
   841	
   842	        usage_ctx
   843	    }
   844	}
