   859	        || spec.about_long.is_some()
   860	        || spec.about_md.is_some()
   861	        || spec.cmd.help_long.is_some()
   862	        || spec.cmd.help_md.is_some()
   863	        || spec.cmd.before_help.is_some()
   864	        || spec.cmd.after_help.is_some()
   865	        || spec.cmd.after_help_long.is_some()
   866	        || !spec.cmd.examples.is_empty()
   867	        || !spec.examples.is_empty()
   868	}
