   870	/// Extract the selected subcommand name from parsed commands.
   871	/// `cmds[0]` is the root command; subsequent entries are subcommands.
   872	pub fn subcommand_name_from_parse(cmds: &[usage::SpecCommand]) -> Option<String> {
   873	    if cmds.len() > 1 {
   874	        let names: Vec<String> = cmds.iter().skip(1).map(|c| c.name.clone()).collect();
